// ── Launcher button icon options ────────────────────────────────────────────
// Names the merchant can choose between in the "Button icon" customizer field.
var LAUNCHER_ICON_NAMES = ['gift', 'star', 'trophy', 'gem'];

export function launcherIconNames() {
    return LAUNCHER_ICON_NAMES.slice();
}

export function icon(name) {
    return ICONS[name] || ICONS['earn-points'];
}

/** Resolves a launcher icon name to its SVG, falling back to 'gift'. */
export function launcherIcon(name) {
    return (name && LAUNCHER_ICON_NAMES.indexOf(name) !== -1) ? ICONS[name] : ICONS['gift'];
}